export const conceptRssXml = "<?xml version=\"1.0\" encoding=\"UTF-8\"?><rss version=\"2.0\"><channel><title>Kurs.ing Blogg</title><description>Norske guider om etablererprøven, skjenkebevilling og salgsbevilling, skrevet for folk som vil bestå kommunens prøve og komme raskt i gang.</description><link>https://www.kurs.ing/guide/</link><language>nb-no</language><item><title>Hvor lang tid tar det å forberede seg til etablererprøven?</title><link>https://www.kurs.ing/guide/blog/hvor-lang-tid-tar-det-a-forberede-seg-til-etablererproven/</link><guid isPermaLink=\"true\">https://www.kurs.ing/guide/blog/hvor-lang-tid-tar-det-a-forberede-seg-til-etablererproven/</guid><description>Mange lurer på hvor lang tid de bør sette av før etablererprøven. Svaret avhenger mindre av bakgrunn og mer av hvordan du faktisk leser.</description><pubDate>Sat, 11 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Hva er forskjellen på salgsbevilling og skjenkebevilling?</title><link>https://www.kurs.ing/guide/blog/forskjellen-pa-salgsbevilling-og-skjenkebevilling/</link><guid isPermaLink=\"true\">https://www.kurs.ing/guide/blog/forskjellen-pa-salgsbevilling-og-skjenkebevilling/</guid><description>Mange blander salgsbevilling og skjenkebevilling. Her er forskjellen forklart enkelt, slik at du vet hvilken rolle, hvilke regler og hvilken prøve som gjelder.</description><pubDate>Sat, 11 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Hva må du kunne for skjenkebevillingsprøven?</title><link>https://www.kurs.ing/guide/blog/hva-ma-du-kunne-for-skjenkebevillingsproven/</link><guid isPermaLink=\"true\">https://www.kurs.ing/guide/blog/hva-ma-du-kunne-for-skjenkebevillingsproven/</guid><description>Skjenkebevillingsprøven handler ikke om å gjette seg frem. Her ser du hvilke regler og temaer som oftest går igjen, og hvordan du kan forberede deg uten å lese for bredt.</description><pubDate>Fri, 10 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Hvordan bestå etablererprøven på første forsøk</title><link>https://www.kurs.ing/guide/blog/hvordan-besta-etablererproven/</link><guid isPermaLink=\"true\">https://www.kurs.ing/guide/blog/hvordan-besta-etablererproven/</guid><description>Etablererprøven handler ikke om pugging alene. Her er en praktisk plan for å lære pensum raskt og møte forberedt hos kommunen.</description><pubDate>Thu, 09 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Salgsbevilling: pensum, krav og vanlige feil før kommunens prøve</title><link>https://www.kurs.ing/guide/blog/salgsbevilling-pensum-og-vanlige-feil/</link><guid isPermaLink=\"true\">https://www.kurs.ing/guide/blog/salgsbevilling-pensum-og-vanlige-feil/</guid><description>For salgsbevilling er det lett å undervurdere detaljene. Her får du oversikt over pensum, rolleansvar og hva du bør øve mest på.</description><pubDate>Thu, 09 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Skjenkebevilling: hva må styrer og stedfortreder kunne før prøven?</title><link>https://www.kurs.ing/guide/blog/skjenkebevilling-hva-ma-styrer-kunne/</link><guid isPermaLink=\"true\">https://www.kurs.ing/guide/blog/skjenkebevilling-hva-ma-styrer-kunne/</guid><description>Mange vet at de må bestå kunnskapsprøven, men færre vet hva rollen som styrer faktisk innebærer. Her er det viktigste du må kunne.</description><pubDate>Thu, 09 Apr 2026 00:00:00 GMT</pubDate></item></channel></rss>";
